class BootCompletedReceiver : BroadcastReceiver() {
    override fun onReceive(context: Context, intent: Intent) {
        // react to the device having finished booting
    }
}

class NetworkChangeReceiver : BroadcastReceiver() {
    override fun onReceive(context: Context, intent: Intent) {
        // The OS expects this to finish executing very quickly —
        // typically within just a few seconds
    }
}

// Implicit broadcast — no specific receiver named,
// any matching registered receiver can respond
sendBroadcast(Intent("com.example.weathernow.SYNC_DONE"))

// Explicit broadcast — targets one specific receiver directly
val intent = Intent(this, SyncCompleteReceiver::class.java)
sendBroadcast(intent)

class SyncStatusReceiver : BroadcastReceiver() {
    override fun onReceive(context: Context, intent: Intent) {
        // Attempting to launch a long coroutine directly here
        // is risky — this receiver object may not exist long
        // enough for it to safely complete
    }
}

// Sent from within WeatherNow's own sync logic
val intent = Intent(this, SyncCompleteReceiver::class.java).apply {
    putExtra("records_synced", 42)
}
sendBroadcast(intent)

class SyncStatusReceiver : BroadcastReceiver() {
    override fun onReceive(context: Context, intent: Intent) {
        val pendingResult = goAsync()
        // a short amount of extra time is granted here
        // to finish a small amount of additional work
        pendingResult.finish()  // signals the OS this receiver is truly done
    }
}
